/* UsimOrdMngMapper.usimOrdMdlInsert */
INSERT INTO MSP_M2M_ORD_MDL
(
    ORD_ID
  , SEQ
  , RPRS_PRDT_ID
  , ORD_CNT
  , DEL_YN

  , REGST_ID
  , REGST_DTTM
  , RVISN_ID
  , RVISN_DTTM
)
VALUES
(
    #{ordId, jdbcType=VARCHAR}
  , (SELECT COUNT(*)+1
     FROM   MSP_M2M_ORD_MDL
     WHERE  ORD_ID = #{ordId, jdbcType=VARCHAR}
     )
  , #{rprsPrdtId, jdbcType=VARCHAR}
  , #{ordCnt, jdbcType=VARCHAR}
  , #{delYn, jdbcType=VARCHAR}

  , #{sessionUserId, jdbcType=VARCHAR}
  , SYSDATE
  , #{sessionUserId, jdbcType=VARCHAR}
  , SYSDATE

)

