/* UsimOrdMngMapper.usimOrdMngListEx */ SELECT A.ORD_ID , A.ORD_DATE , A.ORGN_ID , F_GET_AGENT_NM(A.ORGN_ID) AS ORGN_NM , A.AREA_NM , (SELECT AREA_NM AS TEXT FROM MSP_M2M_ADDR AD WHERE AD.SEQ = A.AREA_NM ) AREA_NM_TEXT , A.MNG_NM , A.MNG_NM AS MASK_MNG_NM , A.TEL_FN1 , A.TEL_MN1 , A.TEL_RN1 , A.TEL_FN2 , A.TEL_MN2 , A.TEL_RN2 , DECODE(A.TEL_FN1, NULL, '', A.TEL_FN1 || '-' || A.TEL_MN1 || '-' || A.TEL_RN1) MNG_PHN , DECODE(A.TEL_FN2, NULL, '', A.TEL_FN2 || '-' || A.TEL_MN2 || '-' || A.TEL_RN2) MNG_MBLPHN , A.ORD_STATUS , FN_GET_CODENM('M2M0001',A.ORD_STATUS) AS ORD_STATUS_NM , A.ORD_INFO , A.TB_CD , FN_GET_CODENM('RCP0025',A.TB_CD) AS TB_CD_NM , A.INV_NO , A.TAKE_DATE , A.WILL_TAKE_DATE , A.SEND_DATE , A.POST , A.ADDR , A.ADDR_BJD , A.ADDR_DTL , A.ADDR_DTL AS MASK_ADDR_DTL , FN_GET_USRNM(A.RVISN_ID) AS USR_NM , BB.RPRS_PRDT_ID , BB.PRDT_CODE , BB.PRDT_NM || CASE WHEN C.MDL_CNT = 1 THEN '' ELSE '(외)' END AS PRDT_NM , CASE WHEN C.MDL_CNT = 1 THEN TO_CHAR(BB.OUT_UNIT_PRIC,'999,999,999') ELSE '' END AS OUT_UNIT_PRIC , (SELECT SUM(ORD_CNT) FROM MSP_M2M_ORD_MDL AAA WHERE AAA.ORD_ID = A.ORD_ID AND AAA.DEL_YN = 'N' ) AS ORD_CNT , (SELECT SUM(AAA.ORD_CNT * BBB.OUT_UNIT_PRIC) FROM MSP_M2M_ORD_MDL AAA ,MSP_M2M_MDL BBB WHERE AAA.ORD_ID = A.ORD_ID AND AAA.RPRS_PRDT_ID = BBB.RPRS_PRDT_ID AND AAA.DEL_YN = 'N' ) AS PRIC , (SELECT SUM(AAA.ORD_CNT * BBB.OUT_UNIT_PRIC * 1.1) FROM MSP_M2M_ORD_MDL AAA ,MSP_M2M_MDL BBB WHERE AAA.ORD_ID = A.ORD_ID AND AAA.RPRS_PRDT_ID = BBB.RPRS_PRDT_ID AND AAA.DEL_YN = 'N' ) AS PRIC_VAT
FROM MSP_M2M_ORD_MST A ,MSP_M2M_ORD_MDL AA ,(SELECT CC.ORD_ID ,MIN(CC.SEQ) SEQ ,COUNT(*) MDL_CNT FROM MSP_M2M_ORD_MDL CC WHERE CC.DEL_YN = 'N' GROUP BY CC.ORD_ID ) C ,MSP_M2M_MDL BB WHERE AA.ORD_ID = A.ORD_ID AND AA.RPRS_PRDT_ID = BB.RPRS_PRDT_ID AND AA.SEQ = C.SEQ AND AA.ORD_ID = C.ORD_ID AND NVL(A.DEL_YN,'N') = 'N'
AND A.ORD_DATE LIKE #{ordDate, jdbcType=VARCHAR} || '%'
AND A.ORD_ID = #{ordId, jdbcType=VARCHAR}
AND A.ORGN_ID = #{orgnId, jdbcType=VARCHAR}
AND A.ORD_STATUS = #{ordStatus, jdbcType=VARCHAR}
AND A.TAKE_DATE LIKE #{takeDate, jdbcType=VARCHAR} || '%'
AND A.WILL_TAKE_DATE LIKE #{willTakeDate, jdbcType=VARCHAR} || '%'
AND A.SEND_DATE LIKE #{sendDate, jdbcType=VARCHAR} || '%'
AND A.AREA_NM LIKE #{areaNm, jdbcType=VARCHAR} || '%'
AND A.ORD_ID IN (SELECT ORD_ID FROM MSP_M2M_ORD_MDL AAA WHERE AAA.RPRS_PRDT_ID = #{rprsPrdtId, jdbcType=VARCHAR} AND NVL(AAA.DEL_YN,'N') = 'N' )
ORDER BY 1

/* UsimOrdMngMapper.usimOrdMngListEx2 */ SELECT A.ORD_ID , A.ORD_DATE , A.ORGN_ID , F_GET_AGENT_NM(A.ORGN_ID) AS ORGN_NM , A.AREA_NM , (SELECT AREA_NM AS TEXT FROM MSP_M2M_ADDR AD WHERE AD.SEQ = A.AREA_NM ) AREA_NM_TEXT , A.MNG_NM , A.MNG_NM AS MASK_MNG_NM , A.TEL_FN1 , A.TEL_MN1 , A.TEL_RN1 , A.TEL_FN2 , A.TEL_MN2 , A.TEL_RN2 , DECODE(A.TEL_FN1, NULL, '', A.TEL_FN1 || '-' || A.TEL_MN1 || '-' || A.TEL_RN1) MNG_PHN , DECODE(A.TEL_FN2, NULL, '', A.TEL_FN2 || '-' || A.TEL_MN2 || '-' || A.TEL_RN2) MNG_MBLPHN , A.ORD_STATUS , FN_GET_CODENM('M2M0001',A.ORD_STATUS) AS ORD_STATUS_NM , A.ORD_INFO , A.TB_CD , FN_GET_CODENM('RCP0025',A.TB_CD) AS TB_CD_NM , A.INV_NO , A.TAKE_DATE , A.WILL_TAKE_DATE , A.SEND_DATE , A.POST , A.ADDR , A.ADDR_BJD , A.ADDR_DTL , A.ADDR_DTL AS MASK_ADDR_DTL , FN_GET_USRNM(A.RVISN_ID) AS USR_NM , BB.RPRS_PRDT_ID , BB.PRDT_CODE , BB.PRDT_NM , BB.OUT_UNIT_PRIC , AA.ORD_CNT , AA.ORD_CNT * BB.OUT_UNIT_PRIC AS PRIC , AA.ORD_CNT * BB.OUT_UNIT_PRIC * 1.1 AS PRIC_VAT
FROM MSP_M2M_ORD_MST A ,MSP_M2M_ORD_MDL AA ,MSP_M2M_MDL BB WHERE AA.ORD_ID = A.ORD_ID AND AA.RPRS_PRDT_ID = BB.RPRS_PRDT_ID AND AA.DEL_YN = 'N' AND NVL(A.DEL_YN,'N') = 'N'
AND A.ORD_DATE LIKE #{ordDate, jdbcType=VARCHAR} || '%'
AND A.ORD_ID = #{ordId, jdbcType=VARCHAR}
AND A.ORGN_ID = #{orgnId, jdbcType=VARCHAR}
AND A.ORD_STATUS = #{ordStatus, jdbcType=VARCHAR}
AND A.TAKE_DATE LIKE #{takeDate, jdbcType=VARCHAR} || '%'
AND A.WILL_TAKE_DATE LIKE #{willTakeDate, jdbcType=VARCHAR} || '%'
AND A.SEND_DATE LIKE #{sendDate, jdbcType=VARCHAR} || '%'
AND A.AREA_NM LIKE #{areaNm, jdbcType=VARCHAR} || '%'
AND A.ORD_ID IN (SELECT ORD_ID FROM MSP_M2M_ORD_MDL AAA WHERE AAA.RPRS_PRDT_ID = #{rprsPrdtId, jdbcType=VARCHAR} AND NVL(AAA.DEL_YN,'N') = 'N' )
ORDER BY 1

/* UsimOrdMngMapper.getMdlIdComboList */ SELECT DISTINCT BB.RPRS_PRDT_ID AS VALUE , BB.PRDT_NM AS TEXT /*, PRDT_CODE||'-'||PRDT_NM AS TEXT*/ FROM MSP_M2M_MDL BB ,MSP_M2M_ORGN_PRDT_REL AA WHERE NVL(BB.USE_YN,'Y') = 'Y' AND AA.RPRS_PRDT_ID(+) = BB.RPRS_PRDT_ID
AND AA.ORGN_ID = #{orgnId, jdbcType=VARCHAR}
ORDER BY TEXT

/* UsimOrdMngMapper.getAreaNmComboList */ SELECT SEQ AS VALUE , AREA_NM AS TEXT FROM MSP_M2M_ADDR WHERE USE_YN = 'Y'
AND ORGN_ID = #{orgnId, jdbcType=VARCHAR}
AND NVL(DEL_YN,'N') = 'N' ORDER BY AREA_NM

/* UsimOrdMngMapper.getM2mMngHTel */
SELECT B.MBLPHN_NUM
FROM MSP_M2M_ORD_MST A
     ,CMN_USR_MST B
WHERE A.ORD_ID = #{ordId, jdbcType=VARCHAR}
AND   A.REGST_ID = B.USR_ID
